import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './AllMaterials.css';

const AllMaterials = () => {
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    fetchAllMaterials();
  }, []);

  const fetchAllMaterials = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/materials');
      const data = await response.json();
      
      if (data.success) {
        setMaterials(data.materials);
      }
    } catch (error) {
      console.error('Error:', error);
    } finally {
      setLoading(false);
    }
  };

  const getTypeStyle = (type) => {
    const types = {
      'notes': { bg: '#dbeafe', color: '#1d4ed8', label: '📄 NOTES' },
      'pyq': { bg: '#fef3c7', color: '#92400e', label: '📝 PYQ' },
      'syllabus': { bg: '#dcfce7', color: '#166534', label: '📋 SYLLABUS' }
    };
    return types[type?.toLowerCase()] || types.notes;
  };

  if (loading) return <div>Loading...</div>;

  return (
    <div className="all-materials">
      <h1>All Study Materials</h1>
      <div className="materials-grid">
        {materials.map(m => {
          const style = getTypeStyle(m.type);
          return (
            <div key={m.id} className="material-card">
              <span style={{background: style.bg, color: style.color}}>
                {style.label}
              </span>
              <h3>{m.title}</h3>
              <p>Course: {m.course}</p>
              <p>Uploaded: {new Date(m.uploaded_at).toLocaleDateString()}</p>
              <button onClick={() => navigate(`/material/${m.id}`)}>View</button>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default AllMaterials;
